############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "parserGraphTool.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
